import{_ as t,o as n,c as i,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"34. Transition To New Instrument Technician Structure","description":"","frontmatter":{"title":"34. Transition To New Instrument Technician Structure","eba":"Health Allied & Managers Admin 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/34-transition-to-new-instrument-technician-structure.md","filePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/34-transition-to-new-instrument-technician-structure.md"}'),s={name:"ebas/has-managers-admin/health-allied-services/classification-staffing/34-transition-to-new-instrument-technician-structure.md"};function r(c,e,o,h,l,u){return n(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_34-transition-to-new-instrument-technician-structure" tabindex="-1">34. Transition To New Instrument Technician Structure <a class="header-anchor" href="#_34-transition-to-new-instrument-technician-structure" aria-label="Permalink to &quot;34. Transition To New Instrument Technician Structure&quot;">​</a></h1><p><strong>34.1</strong> From FFPPOA 1 July 2021, Employees classified as Instrument Technicians will translate to the new Instrument Technician classification structure as follows:</p><p>Current classification New classification Instrument Technician Grade 1 Instrument Technician Grade 1 Instrument Technician Grade 2 Instrument Technician Grade 2 Instrument Technician Grade 3 Instrument Technician Grade 3 Instrument Technician Grade 4 Instrument Technician Grade 4 Instrument Technician Grade 5 Instrument Technician Grade 5 Instrument Technician Grade 6 Dual Qualified Technician (Sterilising &amp; Operating Theatres)</p><p><strong>34.2</strong> Within 3 months of the commencement of the Agreement, the Employers will review the existing Employees classified as Instrument Technicians and confirm in writing to those Employees:</p><p><strong>(a)</strong> to which classification they have translated, effective from FFPPOA 1 July</p><p><strong>(b)</strong> whether their duties change as a result of the translation</p><p><strong>(c)</strong> back payment of wages (if any) effective from FFPPOA 1 July 2021</p><p>SECTION 2 – HEALTH &amp; ALLIED SERVICES EMPLOYEES AND DENTAL ASSISTANTS</p><p><strong>34.3</strong> Where an Employee disagrees with this re-classification, in the first instance the dispute will be dealt with by the AIC. If the matter remains in dispute, it will be dealt with in accordance with Section 1 <a href="/eba/ebas/has-managers-admin/health-allied-services/allowances/17-reimbursement-of-expenses-dhsv.html">clause 17</a> (Dispute Resolution Procedure).</p>',9)])])}const f=t(s,[["render",r]]);export{d as __pageData,f as default};
